from dataclasses import dataclass
from typing import Literal

Ring = Literal["Adopt", "Trial", "Assess", "Hold"]

@dataclass
class BlipScore:
    id: str
    production_evidence: int    # 0-3
    api_stability: int          # 0-3
    security_compliance: int    # 0-3
    community_support: int      # 0-3
    vendor_risk: int            # 0-3
    performance_fit: int        # 0-3
    security_veto: bool = False # CISO can veto Adopt regardless of score

    @property
    def total(self) -> int:
        return (self.production_evidence + self.api_stability +
                self.security_compliance + self.community_support +
                self.vendor_risk + self.performance_fit)

    @property
    def computed_ring(self) -> Ring:
        if self.security_veto:
            return "Assess"   # cannot be Adopt or Trial with CISO veto
        if self.total >= 14: return "Adopt"
        if self.total >= 9:  return "Trial"
        if self.total >= 5:  return "Assess"
        return "Hold"

    def arb_override(self, ring: Ring, reason: str) -> "BlipScoreWithOverride":
        return BlipScoreWithOverride(base=self, override_ring=ring, override_reason=reason)


@dataclass
class BlipScoreWithOverride:
    base: BlipScore
    override_ring: Ring
    override_reason: str  # dissent/override must be documented

    @property
    def final_ring(self) -> Ring:
        return self.override_ring
